-- {"operators": "OUTER_JOIN", "complexity": "low", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": true, "tables": "CUSTOMER,OORDER", "ducklake": true}
SELECT c.C_W_ID, c.C_ID, c.C_LAST, CASE WHEN o.O_ID IS NULL THEN 'no_orders' WHEN o.O_CARRIER_ID IS NULL THEN 'pending' ELSE 'shipped' END AS status FROM dl.CUSTOMER c LEFT JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID;
